request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?modelName ?orgId ?created ?origId ?normId WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId ?origId .
  FILTER(STRENDS(STR(?origId), "1ad939eef40c461dafae27f75a0586d3") || STRENDS(STR(?model), "1ad939eef40c461dafae27f75a0586d3"))
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:organizationId ?orgId . }
  OPTIONAL { ?model tai:modelCreated ?created . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName (COUNT(DISTINCT ?task) AS ?tasks) (COUNT(DISTINCT ?sf) AS ?sequenceFlows) (COUNT(DISTINCT ?mf) AS ?messageFlows) (COUNT(DISTINCT ?gw) AS ?gateways) (COUNT(DISTINCT ?start) AS ?startEvents) (COUNT(DISTINCT ?end) AS ?endEvents)
WHERE {
  ?model a bboExt:Model .
  ?model tai:originalId "1ad939eef40c461dafae27f75a0586d3" .
  ?defs tai:belongsTo ?model .
  ?choreo tai:belongsTo ?defs .
  OPTIONAL { ?task a bboExt:ChoreographyTask . ?task tai:belongsTo ?choreo . }
  OPTIONAL { ?sf a bbo:SequenceFlow . ?sf tai:belongsTo ?choreo . }
  OPTIONAL { ?mf a bboExt:MessageFlow . ?mf tai:belongsTo ?choreo . }
  OPTIONAL { ?gw a bboExt:ExclusiveGateway . ?gw tai:belongsTo ?choreo . }
  OPTIONAL { ?gw2 a bboExt:ParallelGateway . ?gw2 tai:belongsTo ?choreo . }
  OPTIONAL { ?gw3 a bboExt:EventBasedGateway . ?gw3 tai:belongsTo ?choreo . }
  OPTIONAL { ?start a bboExt:StartEvent . ?start tai:belongsTo ?choreo . }
  OPTIONAL { ?end a bboExt:EndEvent . ?end tai:belongsTo ?choreo . }
  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
GROUP BY ?choreo ?choreoName
ORDER BY DESC(?tasks) DESC(?messageFlows)
LIMIT 25
